  public int cleanLog(String apname){
      if(apname==null) return 0;
    Environment env=BDBMgr.getInstance(apname).getDbEnvironment();
    int count=env.cleanLog();
    // Perform an extra checkpoint
    env.checkpoint(new CheckpointConfig().setForce(true));
    env.compress();
    return count;
  }
