  public int delUnusedNodes(String apname){
    if(apname==null) return 0;
    Log log=new Log("log/dbcleanr.log").setIfDisplayTime(true);
    //database v cleaning (d & dv is secondary)
    BDBWorker worker=new BDBWorker(apname);
    DatabaseEntry keyData = new DatabaseEntry();
    DatabaseEntry foundData = new DatabaseEntry();
    int processCount=0;
    try{
      Environment env=BDBMgr.getInstance(apname).getDbEnvironment();
      Transaction txn=env.beginTransaction(null,null);
      SecondaryDatabase db=worker.getValueDomain2DB(worker.getValueDB());
      SecondaryCursor cursor=db.openCursor(txn,null);

      OperationStatus retVal;
      //resume processing
      String status=SystemCache.getInstance().get("dbclean_unuseNode_status_"+apname);
      if(status!=null){
        int domainId= Encoder.parseInt(status);
        TupleBinding.getPrimitiveBinding(Integer.class).objectToEntry(domainId,keyData);
        retVal=cursor.getSearchKey(keyData,foundData,LockMode.DEFAULT);
      }
      else{
        retVal=cursor.getNext(keyData,foundData, LockMode.DEFAULT);
      }

      Account account=Account.getInstance(apname);
      while(retVal==OperationStatus.SUCCESS){
        int domainId=TupleBinding.getPrimitiveBinding(Integer.class).entryToObject(keyData);
        if(processCount>NODE_PER_PROCESS) {
          //save position
          SystemCache.getInstance().put("dbclean_unuseNode_status_"+apname,""+domainId);
          break;
        }

        boolean used=account.hasDomain(domainId);
        if(used || domainId<1000000) {
          try{
            retVal=cursor.getNextNoDup(keyData,foundData,LockMode.DEFAULT);
          }
          catch(SecondaryIntegrityException e){
            log.log("SecondaryIntegrityException @"+domainId);
          }
          continue;
        }
        else{
          cursor.delete();
          processCount++;


          try{
            retVal=cursor.getNext(keyData,foundData,LockMode.DEFAULT);
          }
          catch(SecondaryIntegrityException e){
            log.log(domainId+" SecondaryIntegrityException:"+cursor.count()+"<br>");
          }
        }
      }
      cursor.close();
      txn.commit();
    }
    catch (Exception e){
      log.log(e.getMessage());
      log.log(e);
    }
    finally{
      try{
        worker.commit();
      }
      catch (Exception e){
        log.log(e.getMessage());
        log.log(e);
      }
      return processCount;
    }

  }
  public int delNotifications(String apname){
      long doTime=1000*10;
    Log log=new Log("log/dbcleanr.log").setIfDisplayTime(true);
    List<BDBWorkerCommand> commands = new ArrayList<>();
    int count = 0;
    LocalDateTime startTime = LocalDateTime.now();
    boolean isBreaked = false;
    BDBWorker worker = new BDBWorker(apname);
    try {
      SDBQuery q = new SDBQueryFull(worker);
      q.go(DConst.NF_TIMESTAMP);
      SDBNode node;
      while ((node = q.next()) != null) {

        if (ChronoUnit.MILLIS.between(startTime, LocalDateTime.now()) > doTime) {
          break;//exceeded clean time limit, quit
        }

        long notificationTime = Encoder.parseLong(node.getValue());
        LocalDateTime notificationDateTime = LocalDateTime.ofInstant(
                Instant.ofEpochMilli(notificationTime), ZoneId.systemDefault());
        if (ChronoUnit.DAYS.between(notificationDateTime, startTime) < 7) {
          // match expected condition
          continue;//reading notification within a month, quit
        }

        count++;
        int rootNodeId = node.getId();

        node = q.dipNode(DConst.NF_NOTIFY_TO);
        if(node!=null) commands.add(new BDBWorkerCommandUnlink(DConst.NF_TIMESTAMP, rootNodeId, DConst.NF_NOTIFY_TO, node.getId()));
        node = q.dipNode(DConst.NF_IFREAD);
        if(node!=null) commands.add(new BDBWorkerCommandUnlink(DConst.NF_TIMESTAMP, rootNodeId, DConst.NF_IFREAD, node.getId()));
        node = q.dipNode(DConst.NF_TYPE);
        if(node!=null) commands.add(new BDBWorkerCommandUnlink(DConst.NF_TIMESTAMP, rootNodeId, DConst.NF_TYPE, node.getId()));
        node = q.dipNode(DConst.NF_URL);
        if(node!=null) commands.add(new BDBWorkerCommandUnlink(DConst.NF_TIMESTAMP, rootNodeId, DConst.NF_URL, node.getId()));
        node = q.dipNode(DConst.NF_SUBJECT);
        if(node!=null) commands.add(new BDBWorkerCommandUnlink(DConst.NF_TIMESTAMP, rootNodeId, DConst.NF_SUBJECT, node.getId()));
        node = q.dipNode(DConst.NF_MESSAGE);
        if(node!=null) commands.add(new BDBWorkerCommandUnlink(DConst.NF_TIMESTAMP, rootNodeId, DConst.NF_MESSAGE, node.getId()));

        node = q.dipNode(DConst.NF_SUBJECT);
        if(node!=null) commands.add(new BDBWorkerCommandDelete(DConst.NF_SUBJECT, node.getId()));
        node = q.dipNode(DConst.NF_MESSAGE);
        if(node!=null) commands.add(new BDBWorkerCommandDelete(DConst.NF_MESSAGE, node.getId()));

        commands.add(new BDBWorkerCommandDelete(DConst.NF_TIMESTAMP, rootNodeId));
      }
    } finally {
      worker.commit();
    }

    return commitCommands(apname, commands);
  }
  private int commitCommands(String apname, List<BDBWorkerCommand> commands) {
    BDBWorker worker = new BDBWorker(apname);
    try {
      for (BDBWorkerCommand c : commands) {
          try{
            c.execute(worker);
          }
          catch (SecondaryIntegrityException e){}
      }
    } finally {
      worker.commit();
      //we don't do compress any more because this takes too much time on large db and should not be executed often
      //worker.compress();
      return commands.size();
    }
  }


